+  return {
+    ...cfg,
+    agents: {
+      ...cfg.agents,
+      defaults: {
+        ...cfg.agents?.defaults,
+        model: {
+          ...(existingFallbacks ? { fallbacks: existingFallbacks } : undefined),
+          primary,
+        },
+      },
+    },
+  };
